const usernameField = document.getElementById("username-field"),
    searchForm = document.getElementById("search-form"),
    results = document.getElementById("results"),
    encodedField = document.getElementById("encoded-id"),
    errorElem = document.getElementById("error"),
    idField = document.getElementById("user-id"),
    usernameElem = document.getElementById("username"),
    copyId = document.getElementById("copy-id"),
    copyEncoded = document.getElementById("copy-encoded"),
    submitBtn = document.getElementById("submit-btn");

searchForm.addEventListener("submit", async (e) => {
    e.preventDefault();
    submitBtn.innerText = "Searching...";
    submitBtn.disabled = true;

    const response = await fetch(`https://psn.flipscreen.games/search.php?username=${usernameField.value}`);
    const data = await response.json();

    if (response.status === 200) {
        usernameElem.innerText = data.online_id;
        idField.value = data.user_id;
        encodedField.value = data.encoded_id;
        errorElem.innerText = "";
        searchForm.style.display = "none";
        results.style.display = "block";
    } else {
        errorElem.innerText = data.error;
        submitBtn.innerText = "Submit";
        submitBtn.disabled = false;
    }
});

copyEncoded.addEventListener("click", () => {
    navigator.clipboard.writeText(encodedField.value);
    copyEncoded.innerText = "Copied!";
    window.setTimeout(() => {
        copyEncoded.innerText = "Copy";
    }, 1500);
});

copyId.addEventListener("click", () => {
    navigator.clipboard.writeText(idField.value);
    copyId.innerText = "Copied!";
    window.setTimeout(() => {
        copyId.innerText = "Copy";
    }, 1500);
});